import React from "react";
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from "react-leaflet";

function DestinationSelector({ setDestination }) {

  useMapEvents({
    click(e) {
      setDestination([e.latlng.lat, e.latlng.lng]);
    }
  });

  return null;
}

function Map({ currentLocation, destination, setDestination }) {

  return (

    <MapContainer
      center={currentLocation || [25.5941, 85.1376]}
      zoom={13}
      style={{ height: "400px", width: "100%", marginTop: "20px" }}
    >

      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      <DestinationSelector setDestination={setDestination} />

      {currentLocation && (
        <Marker position={currentLocation}>
          <Popup>Current Location</Popup>
        </Marker>
      )}

      {destination && (
        <Marker position={destination}>
          <Popup>Final Destination</Popup>
        </Marker>
      )}

    </MapContainer>

  );
}

export default Map;
